#!/usr/bin/env python3
"""Inject Frankenstein 2077 FINAL character art (a957-a968) into assets/assets.json. Idempotent.
   12 cyberpunk portraits (Trevor's drawn art). Replaces the earlier SVG placeholders.
Usage (from the repo root, next to build.py):
    python3 apply_frankenstein_2077_art.py
"""
import json, os, sys
ROOT = os.path.dirname(os.path.abspath(__file__))
ASSETS = os.path.join(ROOT, "assets", "assets.json")
ART = {
    'a957': 'data:image/jpeg;base64,',
    'a958': 'data:image/jpeg;base64,',
    'a959': 'data:image/jpeg;base64,',
    'a960': 'data:image/jpeg;base64,',
    'a961': 'data:image/jpeg;base64,',
    'a962': 'data:image/jpeg;base64,',
    'a963': 'data:image/jpeg;base64,',
    'a964': 'data:image/jpeg;base64,',
    'a965': 'data:image/jpeg;base64,',
    'a966': 'data:image/jpeg;base64,',
    'a967': 'data:image/jpeg;base64,',
    'a968': 'data:image/jpeg;base64,'
}

def main():
    if not os.path.isfile(ASSETS):
        sys.exit("ERROR: assets/assets.json not found. Run from the repo root (next to build.py).")
    data = json.load(open(ASSETS, encoding="utf-8"))
    added = skipped = 0
    for k, v in ART.items():
        if data.get(k) == v: skipped += 1
        else: data[k] = v; added += 1
    json.dump(data, open(ASSETS, "w", encoding="utf-8"))
    print(f"Frankenstein 2077 art: {added} written, {skipped} already present (a957-a968).")
    print("Note: a969 (deck box) stays the SVG placeholder unless box art is supplied.")
    print("Next: python3 build.py")

if __name__ == "__main__":
    main()
